// Apps to sync — same list as openapi/apps.yaml
var apps = [
  { fury_app: 'payments',        paths: ['/v1/payments'] },
  { fury_app: 'customers',       paths: ['/v1/customers'] },
  { fury_app: 'preferences',     paths: ['/checkout/preferences'] },
  { fury_app: 'chargebacks',     paths: ['/v1/chargebacks'] },
  { fury_app: 'subscriptions',   paths: ['/preapproval'] },
  { fury_app: 'merchant_orders', paths: ['/merchant_orders'] },
  { fury_app: 'oauth',           paths: ['/oauth/token'] },
  { fury_app: 'payment_methods', paths: ['/v1/payment_methods'] },
  { fury_app: 'stores',          paths: ['/users/{user_id}/stores'] },
  { fury_app: 'pos',             paths: ['/pos'] }
];

return apps.map(function(app) { return { json: app }; });

var yaml = require('js-yaml');
var crypto = require('crypto');

// Inputs from previous nodes
var appItem    = items[0].json;
var specRaw    = $node['Fetch spec from Document Hubs'].data;
var githubFile = $node['Get spec3.yaml from GitHub'].data;
var mainSha    = $node['Get main branch SHA'].data.object.sha;

// Parse incoming spec from Document Hubs
var specText = typeof specRaw === 'string' ? specRaw : JSON.stringify(specRaw);
var incoming;
try { incoming = yaml.safeLoad(specText); }
catch(e) { incoming = JSON.parse(specText); }

// Decode current spec3.yaml from GitHub (base64)
var currentYaml = Buffer.from(githubFile.content, 'base64').toString('utf-8');
var current = yaml.safeLoad(currentYaml);

var allowedPaths = appItem.paths || [];

// Merge schemas
var newSchemas = (incoming.components || {}).schemas || {};
if (!current.components) current.components = {};
if (!current.components.schemas) current.components.schemas = {};

var schemaChanges = [];
Object.keys(newSchemas).forEach(function(name) {
  var schema = newSchemas[name];
  if (!current.components.schemas[name]) {
    current.components.schemas[name] = schema;
    schemaChanges.push('+ schema: ' + name);
  } else if (JSON.stringify(current.components.schemas[name]) !== JSON.stringify(schema)) {
    current.components.schemas[name] = schema;
    schemaChanges.push('~ schema: ' + name);
  }
});

// Merge paths
var incomingPaths = incoming.paths || {};
if (!current.paths) current.paths = {};

var pathChanges = [];
var removals = [];

// Detect removals
var ownedInSpec = Object.keys(current.paths).filter(function(p) {
  return allowedPaths.some(function(prefix) { return p.indexOf(prefix) === 0; });
});
var incomingPathKeys = Object.keys(incomingPaths);
ownedInSpec.forEach(function(p) {
  if (incomingPathKeys.indexOf(p) === -1) {
    removals.push('? no longer in Spec Hub: ' + p);
  }
});

// Add / update paths
Object.keys(incomingPaths).forEach(function(path) {
  var methods = incomingPaths[path];
  if (allowedPaths.length > 0 && !allowedPaths.some(function(prefix) { return path.indexOf(prefix) === 0; })) return;
  if (!current.paths[path]) {
    current.paths[path] = methods;
    pathChanges.push('+ path: ' + path);
  } else {
    Object.keys(methods).forEach(function(method) {
      var op = methods[method];
      if (!current.paths[path][method]) {
        current.paths[path][method] = op;
        pathChanges.push('+ ' + method.toUpperCase() + ' ' + path);
      } else if (JSON.stringify(current.paths[path][method]) !== JSON.stringify(op)) {
        current.paths[path][method] = op;
        pathChanges.push('~ ' + method.toUpperCase() + ' ' + path);
      }
    });
  }
});

var allChanges = schemaChanges.concat(pathChanges);

if (allChanges.length === 0) {
  return [{ json: { skip: true, app: appItem.fury_app, reason: 'no changes' } }];
}

// Build merged YAML
var mergedYaml = yaml.safeDump(current, { lineWidth: 120 });
var contentBase64 = Buffer.from(mergedYaml).toString('base64');

// Build branch name
var hash = crypto.createHash('sha256').update(allChanges.join('|')).digest('hex').slice(0, 8);
var branch = 'enhancement/automatic-spec-' + appItem.fury_app + '/spec3-' + hash;

var commitMessage = 'chore(spec): sync ' + appItem.fury_app + ' from Spec Hub\n\n' +
  allChanges.map(function(c) { return '- ' + c; }).join('\n') +
  (removals.length > 0 ? '\n\n## Paths no longer in Spec Hub (review manually)\n' + removals.map(function(r) { return '- ' + r; }).join('\n') : '');

return [{ json: {
  skip: false,
  app: appItem.fury_app,
  branch: branch,
  mainSha: mainSha,
  contentBase64: contentBase64,
  currentFileSha: githubFile.sha,
  commitMessage: commitMessage,
  changes: allChanges,
  removals: removals
} }];

var item = items[0].json;
console.log('[SKIP] ' + item.app + ': ' + item.reason);
return items;
